func (lg *StoreMsg) WriteMsg(when time.Time, msg string, level int) error {
	m := when.Format("2006-01-02 15:04:05") + " " + msg + "\r\n"
	if len(logMsgs) > MaxMsgLen {
		start := MaxMsgLen - len(m)
		if start <= 0 {
			start = MaxMsgLen
		}
		logMsgs = logMsgs[start:]
	}
	logMsgs += m
	return nil
}
